var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"여기 있었군, 베로니카 양. 오래 찾았네.","JPN":"ここにいたか、ベロニカ。探したぞ。","ENG":"There you are, Veronica. I've been looking everywhere for you.","TWN":"妳在這裡啊，貝洛妮卡，我一直在找妳。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님......?","JPN":"ご主人様……？","ENG":"Master?","TWN":"主人……？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 먼저 인사드렸어야 했는데 오신 줄도 모르고 있었군요.","JPN":"申し訳ございません。いらしたことに気付きませんでした。","ENG":"Apologies. I should have greeted you first. I had no idea you were here.","TWN":"對不起，我應該先向您打聲招呼的，沒想到您先來了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"침식재난 때 자네 고생이 많지 않았나.","JPN":"侵食災害の時はだいぶ苦労をかけてしまってすまない。","ENG":"You've been through a lot during the Corruption Disaster.","TWN":"侵蝕災難的時候，真是辛苦妳了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"소미 양에게 들은 이야기도 신경 쓰는 눈치고.","JPN":"ヒマワリさんから聞いた話も気にしているようだし。","ENG":"And the rumor Ms. Shim told you about seemed to have gotten you all riled up.","TWN":"小美說的話，妳很在意吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......표정을 제대로 간수하지 못했군요. 주의하겠습니다.","JPN":"……表情管理がしっかりできていなかったようですね。気を付けます。","ENG":"I shouldn't have let my emotions show. Please forgive me. It won't happen again.","TWN":"……看來是我表現得太明顯了，我以後會注意的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"질책하려는 건 아닐세. 그냥 자네가 장기 계약을 거절한 사정과 관계가 있는지 해서 말이야.","JPN":"別に責めているわけではない。ただ、君が長期契約を断る理由と関係している気がしてな。","ENG":"I'm not here to scold you. I'm just curious if this has anything to do with why you turned down my long-term offer.","TWN":"我不是責怪妳，我只是在想，妳拒絕和我們續簽，是不是跟這個有關係。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"계약도 며칠 뒤면 끝나지만, 아무래도 마음에 걸려서 말일세.","JPN":"契約はあと数日で終わるんだが、やはり気になってね。","ENG":"I know our contract is over in a few days, but I'm getting worried about you.","TWN":"合約過幾天就到期了，我很擔心啊。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는, 기억이 없습니다.","JPN":"私は、記憶を失いました。","ENG":"I... don't remember anything.","TWN":"我其實什麼都不記得了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 기억 상실이란 말인가?","JPN":"ふむ？　記憶喪失ということか？","ENG":"Huh? You mean you've got amnesia?","TWN":"嗯？妳的意思是妳失憶了？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 모네도 그렇게 말하더군요.","JPN":"はい。モネもそう言っていました。","ENG":"Yes. That's how Mone put it, too.","TWN":"嗯，莫妮也是那麼說的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"깨어났을 때 기억하는 거라고는 제가 메이드였다는 사실과......","JPN":"目が覚めた時に覚えていたのは自分がメイドだったということと……","ENG":"The only thing I remembered when I woke up was that I used to be a maid...","TWN":"我醒來的時候，就只記得我是個女僕……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"소중한 무언가를 지키려고 했다는 것뿐이었어요.","JPN":"大切な何かを守ろうとしていたということだけでした。","ENG":"And that I was trying to protect something precious.","TWN":"並且要守護什麼珍貴的東西。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래서 메이드 일을 하다 보면 기억이 되돌아올 수도 있다는 생각에, 지금처럼 지내고 있었습니다.","JPN":"それで、メイドの仕事をしていれば記憶が戻ってくるかもしれないと思って、今のように過ごしております。","ENG":"I figured my memories might return if I continued to serve as a maid. Hence my current situation.","TWN":"我在想，如果我一直做女僕，是不是哪一天就可以想起來，所以才會這麼過下去。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음. 하지만 한 곳에 오래 머물지 않는 이유가 있나?","JPN":"ふむ。しかし1ヶ所に長く滞在しないのはどんな理由で？","ENG":"Hmm... But is there a reason why you won't stay in one place for long?","TWN":"唔，那妳為什麼不在一個地方停留呢？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"매번 이리저리 옮겨 다니는 것도 고생일 텐데.","JPN":"毎回拠点を変えるのは大変だと思うんだが。","ENG":"It must be a hassle having to move around so much.","TWN":"每次都要換個地方，豈不是很麻煩。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 일을 하면서 이따금 과거의 순간이 떠오를 때도 있었습니다.","JPN":"この仕事をしていると時々、昔の記憶が一瞬だけ蘇る時があります。","ENG":"There have been moments when bits of my past flashed across my mind.","TWN":"這個工作，偶爾會讓我想起過去的某個瞬間。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};